-- Seed financials_cache with 4 coworking samples (parsed from Trendlyne dashboard workbooks).
-- Run AFTER migration 010_financials_cache.sql. Idempotent (upsert on symbol+exchange).
on conflict (symbol, exchange) do update set
  tikr = excluded.tikr, payload = excluded.payload, source = excluded.source, fetched_at = excluded.fetched_at;
